noncompliant:
// Applying unary minus to unsigned variables
uint8_t a = 255;
int32_t b = -a; // Noncompliant; unexpected result

uint32_t c = 1U;
int64_t d = -c; // Noncompliant; gets large positive value

// Direct unary minus on unsigned literal
int value = -1U; // Noncompliant

compliant:
// Use signed variables for negation
int8_t a = 255; // Use signed type
int32_t b = -a; // OK with signed

// Cast to signed before negation
uint32_t c = 1U;
int64_t d = -(int32_t)c; // Cast to signed first

// Use signed literals
int value = -1; // Use signed literal
